import re, unicodedata, difflib

def strip_diacritics(s):
    return ''.join(ch for ch in unicodedata.normalize('NFKD', s) if not unicodedata.combining(ch))

def normalize_ar(s):
    if not s:
        return s
    s = s.replace('ـ','')  # tatweel
    s = strip_diacritics(s)
    # unify hamza forms
    s = (s.replace('أ','ا').replace('إ','ا').replace('آ','ا').replace('ٱ','ا')
             .replace('ى','ي').replace('ؤ','و').replace('ئ','ي').replace('ة','ه'))
    # remove punctuation
    s = re.sub(r'[^\w\s\u0600-\u06FF]', ' ', s)
    # collapse spaces
    s = re.sub(r'\s+', ' ', s).strip()
    return s

def sim_ratio(a, b):
    a_n = normalize_ar(a)
    b_n = normalize_ar(b)
    if not a_n or not b_n:
        return 0.0
    return difflib.SequenceMatcher(None, a_n, b_n).ratio()

def token_f1(a, b):
    a_t = normalize_ar(a).split()
    b_t = normalize_ar(b).split()
    if not a_t or not b_t:
        return 0.0
    a_set, b_set = set(a_t), set(b_t)
    inter = len(a_set & b_set)
    prec = inter / len(a_set)
    rec = inter / len(b_set)
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

def lcs_length(a, b):
    a_n = normalize_ar(a)
    b_n = normalize_ar(b)
    # simple DP
    n, m = len(a_n), len(b_n)
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            tmp=dp[j]
            if a_n[i-1]==b_n[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j], dp[j-1])
            prev=tmp
    return dp[m], n, m

def lcs_ratio(a,b):
    l,n,m = lcs_length(a,b)
    if max(n,m)==0:
        return 0.0
    return l/max(n,m)

